def fmt_mm(value):
    number = float(value)
    text = "{0:.6f}".format(number).rstrip("0").rstrip(".")
    if text == "-0":
        text = "0"
    return text + "mm"


def create_cylinder(oEditor, name, x, y, z_center, radius, height):
    """
    Создать цилиндр в HFSS.
    Для сферической линзы цилиндры ориентированы вдоль оси Z.
    """
    oEditor.CreateCylinder(
        [
            "NAME:CylinderParameters",
            "XCenter:=", fmt_mm(x),
            "YCenter:=", fmt_mm(y),
            "ZCenter:=", fmt_mm(z_center),
            "Radius:=", fmt_mm(radius),
            "Height:=", fmt_mm(height),
            "WhichAxis:=", "Z",
            "NumSides:=", "0",
        ],
        [
            "NAME:Attributes",
            "Name:=", name,
            "Flags:=", "",
            "Color:=", "(255 0 0)",
            "Transparency:=", 0,
            "PartCoordinateSystem:=", "Global",
            "UDMId:=", "",
            "MaterialValue:=", "\"vacuum\"",
            "SurfaceMaterialValue:=", "\"\"",
            "SolveInside:=", True,
            "IsMaterialEditable:=", True,
            "UseMaterialAppearance:=", False,
            "IsLightweight:=", False,
        ],
    )


