# END_EMBEDDED_LAYERS


def _parse_embedded_layers():
    """
    Read all layer data from the embedded JSON string.
    Returns a list of dicts: {"layer": int, "cells": [[x, y, r], ...]}.
    """
    data = json.loads(EMBEDDED_LAYERS_JSON)
    return data.get("layers", [])


def _iter_cells_for_all_layers(target_layer=None):
    """
    Iterator over cells of layers.
    If target_layer is None, iterates over all layers.
    If target_layer is a number, iterates only over that layer.
    For each cell yields (global_index, layer_index, x, y, r).
    """
    layers = _parse_embedded_layers()
    global_idx = 0

    for layer_data in layers:
        layer_num = layer_data["layer"]
        cells = layer_data["cells"]

        # Filter by target_layer if specified
        if target_layer is not None and layer_num != target_layer:
            continue

        for cell in cells:
            # cell is [x, y, r]
            x, y, r = cell
            yield (global_idx, layer_num, x, y, r)
            global_idx += 1


def main():
    """
    Main entry point to be run inside HFSS.
    Creates cylinders for all embedded layers without reading external files.
    """
    ScriptEnv.Initialize("Ansoft.ElectronicsDesktop")
    oDesktop.RestoreWindow()
    oProject = oDesktop.SetActiveProject(PROJECT_NAME)
    oDesign = oProject.SetActiveDesign(DESIGN_NAME)
    oEditor = oDesign.SetActiveEditor("3D Modeler")

    count = 0
    last_layer_num = 0

    # Use LAYER_TO_IMPORT to filter layers (None = all layers)
    for global_idx, layer_num, x, y, r in _iter_cells_for_all_layers(LAYER_TO_IMPORT):
        z_bottom = (layer_num - 1) * CYLINDER_HEIGHT

        name = "Cyl_{0:06d}_L{1:02d}".format(global_idx, layer_num)
        create_cylinder(oEditor, name, x, y, z_bottom, r, CYLINDER_HEIGHT)
        count += 1
        last_layer_num = layer_num

    if LAYER_TO_IMPORT is None:
        print(
            "Created {0} cylinders in {1} layers (embedded data, quadrant only)".format(
                count, last_layer_num
            )
        )
    else:
        print(
            "Created {0} cylinders in layer {1} (embedded data, quadrant only)".format(
                count, LAYER_TO_IMPORT
            )
        )


if __name__ == "__main__":
    main()
